import{_ as a,o as e,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung004.jpg",r="/images/uebung005.jpg",l=JSON.parse('{"title":"Übung Lektion 6","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung06.md","filePath":"lektionen/uebung06.md"}'),d={name:"lektionen/uebung06.md"};function s(u,p,h,y,m,v){return e(),i("div",null,[...p[0]||(p[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-6" tabindex="-1">Übung Lektion 6 <a class="header-anchor" href="#ubung-lektion-6" aria-label="Permalink to &quot;Übung Lektion 6&quot;">​</a></h1><p>A) Bilden Sie mit den in Klammern angegebenen Wurzeln  durch Einsetzen Verbalsätze:</p><p>brāhmaṇas ... (yaj, nṛt, viś, man, yudh, nī, muh)</p><p>ब्राह्मणस् ... यज्, नृत्, विश्, मन्, युध्, नी, मुह्</p><p>brāhmaṇo yajati / yajate. brāhmaṇo nṛtyati. brāhmaṇo viśati. brāhmaṇo manyate. brāhmaṇo yudhyate. brāhmaṇo nayati / nayate. brāhmanō muhyati.</p><p>ब्राह्मणो यजति । ब्राह्मणो यजते । ब्राह्मणो नृत्यति । ब्राह्मणो विशति । ब्राह्मणो मन्यते । ब्राह्मणो युध्यते । ब्राह्मणो नयति । ब्राह्मणो नयते । ब्राह्मणो मुह्यति ।</p><p>devas ... (nṛt, yudh, smṛ, sṛj)</p><p>देवस् ... नृत्, युध्, स्मृ, सृज्</p><p>devo nṛtyati. devo yudhyate. devaḥ smarati. devaḥ sṛjati.</p><p>देवो नृत्यति । देवो युध्यते । देवः स्मरति । देवः सृजति ।</p><p>kavis ... (man, smṛ, viś)</p><p>कविस् ... मन्, स्मृ, विश्</p><p>kavir manyate. kaviḥ smarati. kavir viśati.</p><p>कविर्मन्यते । कविः स्मरति । कविर्विशति ।</p><p>dhenus ... (viś, bhū)</p><p>धेनुस् ... विश्, भू</p><p>dhenur viśati. dhenur bhavati.</p><p>धेनुर्विशति । धेनुर्भवति ॥</p><p>B) Setzen Sie die in Übung A gebildeten Sätze in den Plural</p><p>brāhmaṇā yajanti / yajante / nṛtyanti / viśanti / manyante / yudhyante / nayanti / nayante / muhyanti.</p><p>ब्राह्मणा यजन्ति / यजन्ते / नृत्यन्ति / विशन्ति / मन्यन्ते / युध्यन्ते / नयन्ति / नयन्ते / मुह्यन्ति ।</p><p>devā nṛtyanti. devā yudhyante. devāḥ smaranti. devāḥ sṛjanti.</p><p>देवा नृत्यन्ति । देवा युध्यन्ते । देवाः स्मरन्ति । देवाः सृजन्ति ।</p><p>kavayo manyante. kavayaḥ smaranti. kavayo viśanti.</p><p>कवयो मन्यन्ते । कवयः स्मरन्ति । कवयो विशन्ति ।</p><p>dhenavo viśanti. dhenavo bhavanti.</p><p>धेनेवो विशन्ति । धेनवो भवन्ति ॥</p><p>C) Übersetzen Sie ins Sanskrit:</p><p>1. Er verehrt mit einem Opfer. (Der Opferpriester für einen Opferherrn)</p><p>yajati.</p><p>यजति ।</p><p>2. Śiva tanzt.</p><p>śivo nṛtyati.</p><p>शिवो नृत्यति ।</p><p>3. Rāma führt.</p><p>rāmo nayati.</p><p>रामो नयति ।</p><p>4. Śudras sind verwirrt.</p><p>śūdrā muhyanti.</p><p>शूद्रा मुह्यन्ति ।</p><p>5. Die Kṣatriyafrauen treten ein.</p><p>kṣatriyā viśanti.</p><p>क्षत्रिया विशन्ति ।</p><p>6. Der HERR lässt emanieren.</p><p>īśvaraḥ sṛjati.</p><p>ईश्वरः सृजति ।</p><p>7. Der Kṣatriya verehrt mit einem Opfer. (als Opferherr)</p><p>kṣatriyo yajate.</p><p>क्षत्रियो यजते ।</p><p>8. Śūdrafrauen tanzen.</p><p>śūdrā nṛtyanti.</p><p>शूद्रा नृत्यन्ति ।</p><p>9. Kṣatriyas kämpfen.</p><p>kṣatriyā yudhyante.</p><p>क्षत्रिया युध्यन्ते ।</p><p>10. Heilige Männer führen.</p><p>sādhavo nayanti.</p><p>साधवो नयन्ति ।</p><p>11. Sie erinnern sich.</p><p>smaranti.</p><p>स्मरन्ति ।</p><p>12. Wer (fem.) tanzt?</p><p>kā nṛtyati?</p><p>का नृत्यति ।</p><p>13. Die (erwähnte) Brahmanin tanzt.</p><p>sā brāhmaṇī nṛtyati.</p><p>सा ब्राह्मणी नृत्यति ॥</p><p><img src="'+n+'" alt=""><br> Abb.: kā nṛtyati? = का नृत्यति ।<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>A) Einsetzübung: Bilden Sie Fragen, auf die die Sätze, die sie nach folgenden Einsetzübungen bilden, antworten sind:</p><p>1. devas ... (īśvara, nṛt, sṛj, agni, indra)</p><p>देवस् ... ईश्वर, नृत्, सृज्, अग्नि, इन्द्र</p><p>deva īśvaraḥ. devo nṛtyati. devaḥ sṛjati. devo &#39;gniḥ. deva indraḥ.</p><p>देव ईश्वरः । देवो नृत्यति । देवः सृजति । देवो ऽग्निः । देव इन्द्रः ।</p><p>2. (dvija, sādhu, kavi) ... brāhmaṇaḥ</p><p>द्विज, साधु, कवि ... ब्राह्मणः</p><p>dvijo brāhmaṇaḥ. sādhur brāhmaṇaḥ. kavir brāhmaṇaḥ.</p><p>द्विजो ब्राह्मणः । साधुर्ब्राह्मणः । कविर्ब्राह्मणः ।</p><p>3. (śruti) ... vedaḥ</p><p>श्रुति ... वेदः</p><p>śrutir vedaḥ.</p><p>श्रुतिर्वेदः ।</p><p>4. (veda) ... śrutiḥ</p><p>वेद ... श्रुतिः</p><p>vedaḥ śrutiḥ.</p><p>वेदः श्रुतिः ।</p><p>5. (brāhmaṇa, guru) ... yajanti</p><p>ब्राह्मण, गुरु ... यजन्ति</p><p>brāhmaṇā yajanti. guravo yajanti.</p><p>ब्राह्मणा यजन्ति । गुरवो यजन्ति ।</p><p>6. (devī) ... indrāṇī</p><p>देवी ... इन्द्राणी</p><p>devīndrāṇī.</p><p>देवीन्द्राणी ।</p><p>7. (śūdra, śūdrā, devī) ... nṛtyanti</p><p>शूद्र, शूद्रा, देवी ... नृत्यन्ति</p><p>śūdrā nṛtyanti. śūdrā nṛtyanti. devyo nṛtyanti.</p><p>शूद्रा नृत्यन्ति । शूद्रा नृत्यन्ति । देव्यो नृत्यन्ति ।</p><p>8. (kṣatriya) ... yudhyante</p><p>क्षत्रिय ... युध्यन्ते</p><p>kṣatriyā yudhyante.</p><p>क्षत्रिया युध्यन्ते ।</p><p>9. (brāhmaṇa, brāhmaṇī) ... viśanti</p><p>ब्राह्मण, ब्राह्मणी ... विशन्ति</p><p>brāhmaṇā viśanti. brāhmaṇyo viśanti.</p><p>ब्राह्मणा विशन्ति । ब्राह्मण्यो विशन्ति ।</p><p>10. (guru) ... candrakīrtiḥ</p><p>गुरु ... चन्द्रकीर्तिः</p><p>guruś candrakīrtiḥ.</p><p>गुरुश्चन्द्रकीर्तिः ।</p><p>11. (sādhu) ... rāmaḥ</p><p>साधु ... रामः</p><p>sādhū rāmaḥ.</p><p>साधू रामः ॥</p><p>B)  Setzen Sie in den Plural:</p><p>1. brāhmaṇo yajati.</p><p>ब्राह्मणो यजति |</p><p>brāhmaṇā yajanti.</p><p>ब्राह्मणाः यजन्ति ।</p><p>2. kaiṣā.</p><p>कैषा |</p><p>kā etāḥ</p><p>का एताः ।</p><p>3. kṣatriyo yajate.</p><p>क्षत्रियो यजते |</p><p>kṣatriyā yajante.</p><p>क्षत्रिया यजन्ते ।</p><p>4. sādhvī smarati.</p><p>साध्वी स्मरति |</p><p>sādhvyaḥ smaranti.</p><p>साध्व्यः स्मरन्ति ।</p><p>5. vaiśyā muhyati.</p><p>वैशश्या मुह्यति |</p><p>vaiśyā muhyanti.</p><p>वैश्या मुह्यन्ति ।</p><p>6. sṛjati.</p><p>सृजति |</p><p>sṛjanti.</p><p>सृजन्ति ।</p><p>7. devī manyate.</p><p>देवी मन्यते |</p><p>devyo manyante.</p><p>देव्यो मन्यन्ते ।</p><p>8. gururviśati.</p><p>गुरुर्विशति |</p><p>guravo viśanti.</p><p>गुरवो विशन्ति ।</p><p>9. ko &#39;yam.</p><p>को ऽयम् |</p><p>ka ime / kay ime.</p><p>क इमे । कयिमे ।</p><p>10. iyaṃ devī nṛtyati.</p><p>इयं देवी नृत्यति |</p><p>imā devyo nṛtyanti.</p><p>इमा देव्यो नृत्यन्ति ।</p><p>11. eṣa devo yudhyate.</p><p>एष देवो युध्यते |</p><p>ete devā yudhyante.</p><p>एते देवा युध्यन्ते ।</p><p>12. sa sṛjati.</p><p>स सृजति |</p><p>te sṛjanti.</p><p>ते सृजन्ति ।</p><p>13. paśurdhenuḥ.</p><p>पशुर्धेनुः |</p><p>paśavo dhenavaḥ.</p><p>पशवो धेनवः ।</p><p>14. keyam.</p><p>केयम् |</p><p>kā imāḥ.</p><p>का इमाः ॥स्</p><p>C) Bilden Sie das Ātmanepada zu:</p><p>1. rāmo yajati.</p><p>रामो यजति |</p><p>rāmo yajate.</p><p>रामो यजते ।</p><p>2. kṣatriyā nayanti.</p><p>क्षत्रिया नयन्ति |</p><p>kṣatriyā nayante.</p><p>क्षत्रिया नयन्ते ॥</p><p>D) Bilden Sie das Femininum zu:</p><p>1. śūdro nayati.</p><p>शूद्रो नयति |</p><p>śūdrā nayati.</p><p>शूद्रा नयति.</p><p>2. sādhurviśati.</p><p>साधुर्विशति |</p><p>sādhvī viśati.</p><p>साध्वी विशति ।</p><p>3. brāhmaṇaḥ smarati.</p><p>ब्राह्मणः स्मरति |</p><p>brāhmaṇī smarati.</p><p>ब्राह्मणी स्मरति ।</p><p>4. kṣatriyo yudhyate.</p><p>क्षत्रियो युध्यते |</p><p>kṣatriyā yudhyate. kṣatriyī yudhyate.</p><p>क्षत्रिया युध्यते । क्षत्रियी युध्यते ।</p><p>5. devo guruḥ.</p><p>देवो गुरुः |</p><p>devī gurvī.</p><p>देवी गुर्वी ॥</p><p>E) Übersetzen Sie:</p><p>1. devatānnapūrṇā.</p><p>देवतान्नपूर्णा |</p><p>Annapūrṇā ist eine Gottheit.</p><p>2. śūdretarā.</p><p>शूद्रेतरा |</p><p>Itarā ist eine Śūdrafrau.</p><p>3. vaiśyastulādhāraḥ.</p><p>वैश्यस्तुलाधारः |</p><p>Tulādhara ist ein Vaiśya.</p><p>4. kavirmāghaḥ.</p><p>कविर्माघः |</p><p>Māgha ist ein Dichter.</p><p>5. devyumā.</p><p>देव्युमा |</p><p>Umā ist eine Göttin.</p><p>6. śrutirvedaḥ.</p><p>श्रुतिर्वेदः |</p><p>Der Veda ist Śruti.</p><p>7. dhenurviśati.</p><p>धेनुर्विशति |</p><p>Die Kuh tritt ein.</p><p>8. guruścaitanyaḥ.</p><p>गुरुश्चैतन्यः |</p><p>Caitanya ist ein Meister.</p><p>9. devīndrāṇī.</p><p>देवीन्द्राणी |</p><p>Indrāṇī ist eine Göttin.</p><p>10. sādhurguruḥ.</p><p>साधुर्गुरुः |</p><p>Der Meister ist ein Heiliger.</p><p>11. gururyajate.</p><p>गुरुर्यजते ||</p><p>Der Meister opfert als Opferherr.</p><p>F) Übersetzen Sie ins Sanskrit:</p><p>1. Rāma opfert (als Opferherr).</p><p>rāmo yajate.</p><p>रामो यजते ।</p><p>2. Durgā ist eine Göttin.</p><p>devī durgā.</p><p>देवी दुर्गा ।</p><p>3. Mīnākṣī ist eine Göttin.</p><p>devī mīnākṣī.</p><p>देवी मीनाक्षी ।</p><p>4. Sie sind verwirrt.</p><p>muhyanti.</p><p>मुह्यन्ति ।</p><p>5. Rāma ist ein heiliger Mann.</p><p>sādhū rāmaḥ.</p><p>साधू रामः ।</p><p>6. Wer ist der HERR?</p><p>ka īśvaraḥ.</p><p>क ईश्वरः ।</p><p>7. Indra ist der HERR.</p><p>indra īśvaraḥ.</p><p>इन्द्र ईश्वरः ।</p><p>8. Die Nutztiere treten ein.</p><p>paśavo viśanti.</p><p>पशवो विशन्ति ।</p><p>9. Viṣṇu lässt emanieren = Viṣṇu erschafft.</p><p>viṣṇuḥ sṛjati.</p><p>विष्णुः सृजति ।</p><p>10. Zweimalgeborene sind gut.</p><p>sādhavo dvijātayaḥ.</p><p>साधवो द्विजातयः ।</p><p>11. Das dreifache (Wissen) ist der Sāmaveda, der Ṛgveda und der Yajurveda. (2 Möglichkeiten)</p><p>sāmargyajurvedās trayī. sāmaveda ṛgvedo yajurvedaś ca trayī.</p><p>सामर्ग्यजुर्वेदास्त्रयी । सामवेद ऋग्वेदो यजुर्वेदश्च त्रयी ।</p><p>12. Diese Göttin ist gut.</p><p>sādhvīyaṃ devī / sādhvy eṣā devī / sādhvī sā devī.</p><p>साध्व्यीयं देवी । साध्व्येषा देवी । साध्वी सा देवी.</p><p>13. Die fünf &quot;Qualen&quot; sind: Nichtwissen, Ichwahn, Leidenschaft (Liebe), Hass, Anhänglichkeit an den Leib. (2 Möglichkeiten)</p><p>avidyāsmitārāgadveṣābhniveśāḥ pañca kleśāḥ / avidyāsmitā rāgo dveṣo &#39;bhiniveśaś ca pañca kleśāḥ.</p><p>अविद्यास्मितारागद्वेषाभिनिवेशाः पञ्च क्लेशाः । अविद्यास्मिता रागो द्वेषो ऽभिनिवेशश्च पञ्च क्लेषाः ।</p><p>14. &quot;Verweilungszustände Brahmas&quot; sind: freundliches Wohlwollen, Mitgefühl, Mitfreude, Gleichmut. (2 Möglichkeiten)</p><p>maitrīkaruṇāmuditopekṣā brahmavihārāḥ / maitrī karuṇā muditopekṣā (ca) brahmavihārāḥ.</p><p>मैत्रीकरुणामुदितोपेक्षा ब्रह्मविहाराः । मैत्री करुणा मुदितोपेक्षा (च) ब्रह्मविहाराः ।</p><p>15. Diese Brahmanen opfern im Auftrag anderer.</p><p>ete / ime brāhmaṇā yajanti.</p><p>एते / इमे ब्राह्मणा यजन्ति ।</p><p>16. Brahmanen, Kṣatriyas und Vaśyas sind Zweimalgeborene. (2 Möglichkeiten)</p><p>dvijātayo brāhmaṇakṣatriyavaiśyāḥ / dvijātayo bṛāhmaṇāḥ kṣatriyā vaiśyāś ca.</p><p>द्विजातयो ब्राह्मणक्षत्रियवैश्याः । द्विजातयो ब्राह्मणाः क्षत्रिया वैश्याश्च् ।</p><p>17. Die Wissenschaften (für eine Fürsten) sind: Philosophie, das dreifache (Vedawissen), Ökonomie und Politik. (2 Möglichkeiten)</p><p>ānvīkṣikītrayīvārttādaṇḍanītayo vidyāḥ / ānvīkṣikī trayī vārttā daṇḍanītiś ca vidyāḥ.</p><p>आन्वीक्षिकीत्रयीवार्त्तादण्डनीतयो विद्याः । आन्वीक्षिकी त्रयी वार्त्ता दण्डनीतिश्च विद्याः ।</p><p>18 .Geht es Ihnen gut?</p><p>kiṃ kuśalam?</p><p>किं कुशलम् ।</p><p>19. (Es geht mir) in jeder Hinsicht gut.</p><p>sarvathā kuśalam.</p><p>सर्वथा कुशलम् ॥</p><p><img src="'+r+'" alt=""><br> Abb.: devatānnapūrṇā = देवतान्नपूर्णा<br> Annapurna (अन्नपूर्ण) I, Nepal (नेपाल)<br> [Bildquelle: Wolfgang Beyer / Wikipedia. -- GNU FDLicense]</p>',294)])])}const k=a(d,[["render",s]]);export{l as __pageData,k as default};
